#!/usr/bin/env node
/**
 * Generates the exhaustive API reference for the docs site from the SDK's TSDoc
 * comments, via TypeDoc + typedoc-plugin-markdown. The reference is produced
 * from source on every run, so it can never drift from the code.
 *
 *   pnpm docs:api
 *
 * Output:
 *   packages/demo/content/reference.md        — index
 *   packages/demo/content/reference/<sym>.md  — one page per export
 *   packages/demo/lib/reference-routes.ts     — sidebar entries
 *
 * These files are generated — do not edit them by hand.
 */
import { execSync } from 'node:child_process'
import { readFileSync, writeFileSync, readdirSync, rmSync, mkdirSync } from 'node:fs'
import { join, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'
import { tmpdir } from 'node:os'

const root = join(dirname(fileURLToPath(import.meta.url)), '..')
const demo = join(root, 'packages/demo')
const refDir = join(demo, 'content/reference')
const tmp = join(tmpdir(), `td-${Date.now()}`)

console.log('running TypeDoc…')
execSync(
  [
    'pnpm exec typedoc',
    '--plugin typedoc-plugin-markdown',
    '--entryPoints packages/sdk/src/index.ts',
    '--tsconfig packages/sdk/tsconfig.json',
    `--out ${tmp}`,
    '--readme none',
    '--flattenOutputFiles',
    '--gitRevision main',
    '--excludeInternal',
  ].join(' '),
  { cwd: root, stdio: 'inherit' },
)

/** `Class.RpcClient.md` → { kind:'Class', name:'RpcClient', slug:'rpcclient' } */
function describe(file) {
  const [kind, ...rest] = file.replace(/\.md$/, '').split('.')
  const name = rest.join('.')
  return { kind, name, slug: name.toLowerCase() }
}

/** Drop TypeDoc's breadcrumb/header block and the leading H1. */
function stripHeader(md) {
  const lines = md.split('\n')
  const h1 = lines.findIndex((l) => /^# /.test(l))
  return (h1 === -1 ? lines : lines.slice(h1 + 1)).join('\n').replace(/^\n+/, '')
}

/** Rewrite TypeDoc's relative .md links to site routes. */
function rewriteLinks(md) {
  return md
    .replace(/\]\(README\.md(#[^)]*)?\)/g, '](/docs/reference$1)')
    .replace(
      /\]\([A-Za-z]+\.([A-Za-z0-9_]+)\.md(#[^)]*)?\)/g,
      (_m, name, anchor = '') => `](/docs/reference/${name.toLowerCase()}${anchor})`,
    )
}

const fm = (title, description) =>
  `---\ntitle: ${title}\ndescription: ${description}\ngenerated: true\n---\n\n`

// Reset the output directory.
rmSync(refDir, { recursive: true, force: true })
mkdirSync(refDir, { recursive: true })

const files = readdirSync(tmp).filter((f) => f.endsWith('.md'))
const KIND_LABEL = {
  Class: 'Classes',
  Interface: 'Interfaces',
  Function: 'Functions',
  TypeAlias: 'Type Aliases',
  Variable: 'Variables',
  Enumeration: 'Enums',
}
const KIND_ORDER = Object.keys(KIND_LABEL)
const grouped = {}

for (const file of files) {
  const body = rewriteLinks(stripHeader(readFileSync(join(tmp, file), 'utf8')))

  if (file === 'README.md') {
    writeFileSync(
      join(demo, 'content/reference.md'),
      fm('API Reference', 'Complete, generated reference for every stellar-lens export.') + body,
    )
    continue
  }

  const { kind, name, slug } = describe(file)
  writeFileSync(join(refDir, `${slug}.md`), fm(name, `${kind} ${name} — stellar-lens API reference.`) + body)
  ;(grouped[kind] ??= []).push({ title: name, href: `/docs/reference/${slug}` })
}

// Build the sidebar item list: Overview first, then grouped by kind.
const items = [{ title: 'Overview', href: '/docs/reference' }]
for (const kind of KIND_ORDER) {
  for (const it of (grouped[kind] ?? []).sort((a, b) => a.title.localeCompare(b.title))) {
    items.push(it)
  }
}

writeFileSync(
  join(demo, 'lib/reference-routes.ts'),
  '// Generated by scripts/gen-api-reference.mjs. Do not edit.\n' +
    "import type { DocItem } from './docroutes'\n\n" +
    'export const referenceItems: DocItem[] = ' +
    JSON.stringify(items, null, 2) +
    '\n',
)

rmSync(tmp, { recursive: true, force: true })
console.log(`generated ${files.length} reference page(s) → content/reference/`)
